import styleRegistration from "./Registration.module.css";
import React from "react";
import InputText from "./inputText/InputText";

const Registration = () => {
  /*const arr = {
    value: ["Nickname", "Email", "Password"],
    placeholder: [
      "Например: Explore23",
      "Например: explore@gmail.com",
      "Например: 230cd_3rD",
    ],
  };*/
  const arr = [
    {
      value: "Nickname",
      placeholder: "Например: Explore23",
    },
    {
      value: "Email",
      placeholder: "Например: explore@gmail.com",
    },
    {
      value: "Password",
      placeholder: "Например: 230cd_3rD",
    },
  ];

  const formElem = arr.map(({ value }, { placeholder }, i) => (
    <InputText key={i} value={value} placeholder={placeholder} />
  ));
  return (
    <div>
      <form className={styleRegistration.container}>
        <div>{formElem}</div>
        <button className={styleRegistration.button}>Регистрация</button>
      </form>
    </div>
  );
};

export default Registration;
